CREATE TABLE IF NOT EXISTS public._cou_um(csv_name text PRIMARY KEY, user_id uuid);
CREATE TABLE IF NOT EXISTS public._cou_om(orphan_title text PRIMARY KEY, ticket_id uuid);
CREATE TABLE IF NOT EXISTS public._cou_tl(csv_name text, ticket_ref text, is_orphan boolean, discipline log_discipline, hours numeric, note text, logged_at timestamptz);
CREATE TABLE IF NOT EXISTS public._cou_cr(csv_name text, ticket_ref text, discipline assignee_slot, delta_h numeric, reason text, status text, decided_at timestamptz, created_at timestamptz);
ALTER TABLE public._cou_um ENABLE ROW LEVEL SECURITY;
ALTER TABLE public._cou_om ENABLE ROW LEVEL SECURITY;
ALTER TABLE public._cou_tl ENABLE ROW LEVEL SECURITY;
ALTER TABLE public._cou_cr ENABLE ROW LEVEL SECURITY;
CREATE POLICY "service only" ON public._cou_um FOR ALL USING (false) WITH CHECK (false);
CREATE POLICY "service only" ON public._cou_om FOR ALL USING (false) WITH CHECK (false);
CREATE POLICY "service only" ON public._cou_tl FOR ALL USING (false) WITH CHECK (false);
CREATE POLICY "service only" ON public._cou_cr FOR ALL USING (false) WITH CHECK (false);
